void kernel_syrk(int n, int m, DATA_TYPE alpha, DATA_TYPE beta, DATA_TYPE POLYBENCH_2D(C,N,N,n,n), DATA_TYPE POLYBENCH_2D(A,N,M,n,m)) {
  int i, j, k;
  // 1. 先统一对 C 进行 beta 缩放，保证连续内存写入
  for (i = 0; i < _PB_N; i++) {
    for (j = 0; j <= i; j++) {
      C[i][j] *= beta;
    }
  }
  // 2. 交换循环顺序，将 k 移到外层，i 和 j 在内层，并进行分块(Tiling)或向量化
  // 这样 A[i][k] 在内层循环中是循环不变的，A[j][k] 的访问可以通过转置或局部累加优化
  for (i = 0; i < _PB_N; i++) {
    for (k = 0; k < _PB_M; k++) {
      DATA_TYPE temp = alpha * A[i][k];
      #pragma omp simd
      for (j = 0; j <= i; j++) {
        C[i][j] += temp * A[j][k];
      }
    }
  }
}

#pragma omp parallel for private(j, k) schedule(static)
for (i = 0; i < _PB_N; i++) {
  for (j = 0; j <= i; j++) {
    C[i][j] *= beta;
  }
  for (k = 0; k < _PB_M; k++) {
    DATA_TYPE temp = alpha * A[i][k];
    #pragma omp simd
    for (j = 0; j <= i; j++) {
      C[i][j] += temp * A[j][k];
    }
  }
}
